+        let mut train = SpikeTrain::with_capacity(max_spikes);
+
+        // ... spike encoding logic ...
+
+        trains.push(train);
+    }
+
+    trains
+}
+```
+
+**Expected Improvement**: 30-50% fewer allocations = **1.5x faster**
+
+**Impact**: MEDIUM - Used in attention mechanisms
+
