+      const totalUsage = entries.reduce((sum, e) => sum + e.usageCount, 0);
+
+      return JSON.stringify({
+        total_patterns: this.patterns.size,
+        total_samples: totalSamples,
+        avg_confidence: avgConfidence,
+        total_usage: totalUsage
+      });
+    }
